export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private preferencesService: PreferencesService | undefined;

parameters.new_string:
async send(payload: NotificationPayload): Promise<Notification | null> {
  const recipient = payload.recipient;

  // Chain onto the existing queue for this recipient to preserve ordering.
  // Each send waits for the previous send to the same recipient to finish
  // before starting, ensuring notifications arrive in submission order.
  const previous = this.recipientQueues.get(recipient) ?? Promise.resolve(null);
  const current = previous.then(() => this.doSend(payload));

  this.recipientQueues.set(recipient, current);

  try {
    return await current;
  } finally {
    // Clean up the queue entry if this was the last item
    if (this.recipientQueues.get(recipient) === current) {
      this.recipientQueues.delete(recipient);
    }
  }
}

private async doSend(payload: NotificationPayload): Promise<Notification | null> {
  // Check user preferences before sending
  if (this.preferencesService) {
    const userId = payload.metadata?.['userId'] as string | undefined ?? payload.recipient;
    if (!this.preferencesService.shouldSend(userId, payload.channel, payload.type)) {
      this.logger.info(
        `Notification suppressed by user preferences: ${payload.type} to ${payload.recipient}`,
      );
      return null;
    }
  }

  const adapter = this.adapters.get(payload.channel);

  const notification: Notification = {
    id: generateNotificationId(),
    recipient: payload.recipient,
    type: payload.type,
    channel: payload.channel,
    subject: payload.subject,
    body: payload.body,
    status: 'pending',
    metadata: payload.metadata,
    sentAt: new Date(),
  };

  if (!adapter) {
    notification.status = 'failed';
    this.notifications.push(notification);
    this.logger.warn(`No adapter registered for channel: ${payload.channel}`);

    await this.eventBus.emit({
      type: 'notification:failed',
      recipient: payload.recipient,
      channel: payload.channel,
      error: `No adapter registered for channel: ${payload.channel}`,
      timestamp: new Date(),
    });

    return notification;
  }

  const result = await adapter.send(payload);

  notification.status = result.success ? 'sent' : 'failed';
  this.notifications.push(notification);

  if (result.success) {
    this.logger.info(`Notification sent: ${notification.id} to ${payload.recipient}`);
    await this.eventBus.emit({
      type: 'notification:sent',
      notification,
      timestamp: new Date(),
    });
  } else {
    this.logger.warn(`Notification failed: ${notification.id} — ${result.error}`);
    await this.eventBus.emit({
      type: 'notification:failed',
      recipient: payload.recipient,
      channel: payload.channel,
      error: result.error ?? 'Unknown error',
      timestamp: new Date(),
    });
  }

  return notification;
}

