it('should deliver notifications to the same recipient in order', async () => {
  // Simulate an adapter where each call takes a different amount of time.
  // Without queuing, the second (faster) notification would arrive first.
  let resolveFirst: () => void;
  const firstBlocks = new Promise<void>((r) => { resolveFirst = r; });
  let callIndex = 0;

  service.registerAdapter({
    channel: 'email',
    async send() {
      const idx = callIndex++;
      if (idx === 0) {
        // First notification is slow
        await firstBlocks;
      }
      // Second notification completes immediately
      return { success: true };
    },
  });

  const p1 = service.send({
    recipient: 'user@example.com',
    type: 'order-confirmation',
    channel: 'email',
    subject: 'Order Placed',
    body: 'Your order has been placed.',
  });

  const p2 = service.send({
    recipient: 'user@example.com',
    type: 'order-status-update',
    channel: 'email',
    subject: 'Payment Confirmed',
    body: 'Your payment has been confirmed.',
  });

  // Unblock the first (slow) notification
  resolveFirst!();

  const [n1, n2] = await Promise.all([p1, p2]);

  const notifications = service.getNotifications();
  expect(notifications).toHaveLength(2);
  // Order placed must arrive before payment confirmed
  expect(notifications[0]?.subject).toBe('Order Placed');
  expect(notifications[1]?.subject).toBe('Payment Confirmed');
  expect(n1!.id).toBe(notifications[0]?.id);
  expect(n2!.id).toBe(notifications[1]?.id);
});

it('should not block notifications to different recipients', async () => {
  let resolveFirst: () => void;
  const firstBlocks = new Promise<void>((r) => { resolveFirst = r; });
  const deliveryOrder: string[] = [];

  service.registerAdapter({
    channel: 'email',
    async send(payload) {
      if (payload.recipient === 'slow@example.com') {
        await firstBlocks;
      }
      deliveryOrder.push(payload.recipient);
      return { success: true };
    },
  });

  const p1 = service.send({
    recipient: 'slow@example.com',
    type: 'system-alert',
    channel: 'email',
    subject: 'Slow',
    body: 'Slow delivery.',
  });

  const p2 = service.send({
    recipient: 'fast@example.com',
    type: 'system-alert',
    channel: 'email',
    subject: 'Fast',
    body: 'Fast delivery.',
  });

  // fast@example.com should complete without waiting for slow@example.com
  await p2;
  expect(deliveryOrder).toContain('fast@example.com');

  resolveFirst!();
  await p1;
  expect(deliveryOrder).toEqual(['fast@example.com', 'slow@example.com']);
});

